    req.user = jwt.verify(header.slice(7), process.env.JWT_SECRET, {
      algorithms: ['HS256'],
    });
    next();
  } catch {
    return res.sendStatus(401);
  }
}

app.get('/users', requireAuth, (req, res) => {
  // also consider: only return the caller's own record, or enforce RBAC
  res.json([ /* ... */ ]);
});
